import{_ as e,o,c as d,ag as a}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"Monitoring & Observability","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/monitoring.md","filePath":"admin-ui/monitoring.md"}'),i={name:"admin-ui/monitoring.md"};function s(n,t,r,c,l,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="monitoring-observability" tabindex="-1">Monitoring &amp; Observability <a class="header-anchor" href="#monitoring-observability" aria-label="Permalink to &quot;Monitoring &amp; Observability&quot;">​</a></h1><p>Proxy Smart includes a comprehensive monitoring system covering OAuth flows, FHIR server health, consent decisions, and admin audit events. Each subsystem provides real-time SSE streams, REST query endpoints, and JSONL export.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Subsystem</th><th>Prefix</th><th>SSE Streams</th><th>REST Endpoints</th><th>Log Files</th></tr></thead><tbody><tr><td><strong>OAuth</strong></td><td><code>/monitoring/oauth</code></td><td>2 (events, analytics)</td><td>5</td><td><code>logs/oauth-metrics/</code></td></tr><tr><td><strong>FHIR Health</strong></td><td><code>/monitoring/fhir</code></td><td>2 (checks, summaries)</td><td>2</td><td><code>logs/fhir-health/</code></td></tr><tr><td><strong>FHIR Proxy</strong></td><td><code>/monitoring/fhir-proxy</code></td><td>2 (events, analytics)</td><td>2</td><td>—</td></tr><tr><td><strong>Auth Events</strong></td><td><code>/monitoring/auth</code></td><td>2 (events, analytics)</td><td>2</td><td>—</td></tr><tr><td><strong>Email Events</strong></td><td><code>/monitoring/email</code></td><td>2 (events, analytics)</td><td>2</td><td>—</td></tr><tr><td><strong>Consent</strong></td><td><code>/monitoring/consent</code></td><td>2 (events, analytics)</td><td>3</td><td><code>logs/consent-metrics/</code></td></tr><tr><td><strong>Admin Audit</strong></td><td><code>/monitoring/admin-audit</code></td><td>2 (events, analytics)</td><td>3</td><td><code>logs/admin-audit/</code></td></tr><tr><td><strong>System Status</strong></td><td><code>/health</code>, <code>/status</code></td><td>—</td><td>2</td><td><code>logs/keycloak/</code></td></tr></tbody></table><p>All monitoring endpoints require a valid Bearer token. SSE endpoints also accept a <code>?token=</code> query parameter (since <code>EventSource</code> cannot send custom headers).</p><h2 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h2><p>The <strong>Monitoring</strong> tab in the admin dashboard is a tabbed container with:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Content</th></tr></thead><tbody><tr><td><strong>Dashboard</strong></td><td>OAuth flow summary stats + FHIR server uptime widget</td></tr><tr><td><strong>FHIR Proxy</strong></td><td>Proxied FHIR request metrics — throughput, response times, error rates by server and resource type</td></tr><tr><td><strong>OAuth</strong></td><td>Live OAuth event table and analytics charts with predictive insights</td></tr><tr><td><strong>Auth</strong></td><td>Keycloak authentication events (logins, failures, session activity)</td></tr><tr><td><strong>Email</strong></td><td>Email delivery events from Keycloak (verification, password reset)</td></tr><tr><td><strong>Door Access</strong></td><td>Physical access events from Kisi/UniFi access control integrations</td></tr><tr><td><strong>Consent</strong></td><td>Consent decision monitoring dashboard</td></tr><tr><td><strong>Audit Log</strong></td><td>Admin audit event log with filtering and JSONL export</td></tr></tbody></table><p>FHIR server health is also shown on the main <strong>Dashboard</strong> page as a status card.</p><h2 id="oauth-monitoring" tabindex="-1">OAuth Monitoring <a class="header-anchor" href="#oauth-monitoring" aria-label="Permalink to &quot;OAuth Monitoring&quot;">​</a></h2><p>Tracks all OAuth 2.0 authorization flows: token requests, refresh grants, authorization codes, errors.</p><h3 id="endpoints-—-monitoring-oauth" tabindex="-1">Endpoints — <code>/monitoring/oauth</code> <a class="header-anchor" href="#endpoints-—-monitoring-oauth" aria-label="Permalink to &quot;Endpoints — `/monitoring/oauth`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time OAuth flow events</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query events (filter: <code>limit</code>, <code>type</code>, <code>status</code>, <code>clientId</code>, <code>since</code>)</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot (totals, rates, top clients, hourly stats)</td></tr><tr><td><code>GET</code></td><td><code>/health</code></td><td>REST</td><td>System health metrics + alerts</td></tr><tr><td><code>GET</code></td><td><code>/analytics/export</code></td><td>REST</td><td>Download analytics as JSON</td></tr><tr><td><code>GET</code></td><td><code>/events/export</code></td><td>REST</td><td>Download event log as JSONL</td></tr></tbody></table><h3 id="analytics-fields" tabindex="-1">Analytics Fields <a class="header-anchor" href="#analytics-fields" aria-label="Permalink to &quot;Analytics Fields&quot;">​</a></h3><ul><li><code>totalRequests</code>, <code>successfulRequests</code>, <code>failedRequests</code>, <code>successRate</code></li><li><code>averageResponseTime</code>, <code>activeTokens</code></li><li><code>topClients</code> — ranked by request count with per-client success rate</li><li><code>flowsByType</code> — breakdown by grant type (authorization_code, refresh_token, etc.)</li><li><code>errorsByType</code> — breakdown by error category</li><li><code>hourlyStats</code> — time series (hour, success, error, total)</li><li><code>predictiveInsights</code> — trend direction, next-hour forecast, anomaly risk assessment</li><li><code>weekdayInsights</code> — per-weekday averages with projections</li></ul><h3 id="websocket-transport" tabindex="-1">WebSocket Transport <a class="header-anchor" href="#websocket-transport" aria-label="Permalink to &quot;WebSocket Transport&quot;">​</a></h3><p>An alternative WebSocket transport is available at <code>/oauth/monitoring/websocket</code> supporting bidirectional messaging (subscribe, unsubscribe, filter, ping/pong). Connection info at <code>GET /oauth/monitoring/websocket/info</code>.</p><h3 id="log-files" tabindex="-1">Log Files <a class="header-anchor" href="#log-files" aria-label="Permalink to &quot;Log Files&quot;">​</a></h3><ul><li><code>logs/oauth-metrics/oauth-events.jsonl</code> — event log (one JSON object per line)</li><li><code>logs/oauth-metrics/oauth-analytics.json</code> — latest analytics snapshot</li><li><code>logs/oauth-metrics/system-health.json</code> — latest health snapshot</li></ul><h2 id="fhir-server-health-monitoring" tabindex="-1">FHIR Server Health Monitoring <a class="header-anchor" href="#fhir-server-health-monitoring" aria-label="Permalink to &quot;FHIR Server Health Monitoring&quot;">​</a></h2><p>Background poller that checks all configured FHIR servers every 30 seconds.</p><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><ol><li>On startup, <code>FhirHealthLogger</code> initializes and replays recent checks from JSONL</li><li><code>start()</code> begins polling — hits each FHIR server&#39;s metadata endpoint</li><li>Each check produces a <code>FhirHealthCheck</code> with status (<code>healthy</code>, <code>degraded</code>, <code>unhealthy</code>) and response time</li><li>Results are persisted to JSONL and broadcast to SSE subscribers</li><li>After each full sweep, uptime summaries are computed and broadcast</li></ol><h3 id="endpoints-—-monitoring-fhir" tabindex="-1">Endpoints — <code>/monitoring/fhir</code> <a class="header-anchor" href="#endpoints-—-monitoring-fhir" aria-label="Permalink to &quot;Endpoints — `/monitoring/fhir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/checks/stream</code></td><td>SSE</td><td>Real-time per-check results</td></tr><tr><td><code>GET</code></td><td><code>/summaries/stream</code></td><td>SSE</td><td>Uptime summaries after each sweep</td></tr><tr><td><code>GET</code></td><td><code>/checks</code></td><td>REST</td><td>Query checks (filter: <code>serverUrl</code>, <code>limit</code>, <code>since</code>)</td></tr><tr><td><code>GET</code></td><td><code>/summaries</code></td><td>REST</td><td>Per-server uptime summaries</td></tr></tbody></table><h3 id="summary-fields-per-server" tabindex="-1">Summary Fields (per server) <a class="header-anchor" href="#summary-fields-per-server" aria-label="Permalink to &quot;Summary Fields (per server)&quot;">​</a></h3><ul><li><code>serverName</code>, <code>serverUrl</code>, <code>currentStatus</code></li><li><code>uptimePercent</code> — percentage of healthy checks</li><li><code>avgResponseTimeMs</code> — average response time across all checks</li><li><code>checksTotal</code>, <code>checksHealthy</code></li><li><code>lastChecked</code>, <code>lastError</code></li><li><code>recentChecks</code> — last ~1 hour of individual check results</li></ul><h3 id="log-files-1" tabindex="-1">Log Files <a class="header-anchor" href="#log-files-1" aria-label="Permalink to &quot;Log Files&quot;">​</a></h3><ul><li><code>logs/fhir-health/health-checks.jsonl</code> — check history</li></ul><h3 id="memory-limits" tabindex="-1">Memory Limits <a class="header-anchor" href="#memory-limits" aria-label="Permalink to &quot;Memory Limits&quot;">​</a></h3><p>Ring buffer holds 2,880 entries per server (~24 hours at 30-second intervals).</p><h2 id="fhir-proxy-monitoring" tabindex="-1">FHIR Proxy Monitoring <a class="header-anchor" href="#fhir-proxy-monitoring" aria-label="Permalink to &quot;FHIR Proxy Monitoring&quot;">​</a></h2><p>Tracks all proxied FHIR requests with per-request metrics.</p><h3 id="endpoints-—-monitoring-fhir-proxy" tabindex="-1">Endpoints — <code>/monitoring/fhir-proxy</code> <a class="header-anchor" href="#endpoints-—-monitoring-fhir-proxy" aria-label="Permalink to &quot;Endpoints — `/monitoring/fhir-proxy`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time proxied request events</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query proxied request events</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot (throughput, response times, errors)</td></tr></tbody></table><h3 id="tracked-fields" tabindex="-1">Tracked Fields <a class="header-anchor" href="#tracked-fields" aria-label="Permalink to &quot;Tracked Fields&quot;">​</a></h3><p>Each proxied request logs: server name, HTTP method, resource path, resource type, status code, response time (ms), client ID, and error details (if any).</p><h2 id="auth-event-monitoring" tabindex="-1">Auth Event Monitoring <a class="header-anchor" href="#auth-event-monitoring" aria-label="Permalink to &quot;Auth Event Monitoring&quot;">​</a></h2><p>Polls Keycloak authentication events (login, logout, session expiry, failed attempts) every 60 seconds.</p><h3 id="endpoints-—-monitoring-auth" tabindex="-1">Endpoints — <code>/monitoring/auth</code> <a class="header-anchor" href="#endpoints-—-monitoring-auth" aria-label="Permalink to &quot;Endpoints — `/monitoring/auth`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time auth events</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query auth events</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot</td></tr></tbody></table><h2 id="email-event-monitoring" tabindex="-1">Email Event Monitoring <a class="header-anchor" href="#email-event-monitoring" aria-label="Permalink to &quot;Email Event Monitoring&quot;">​</a></h2><p>Polls Keycloak email delivery events (verification emails, password resets, account notifications) every 60 seconds.</p><h3 id="endpoints-—-monitoring-email" tabindex="-1">Endpoints — <code>/monitoring/email</code> <a class="header-anchor" href="#endpoints-—-monitoring-email" aria-label="Permalink to &quot;Endpoints — `/monitoring/email`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time email events</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query email events</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot</td></tr></tbody></table><h2 id="consent-monitoring" tabindex="-1">Consent Monitoring <a class="header-anchor" href="#consent-monitoring" aria-label="Permalink to &quot;Consent Monitoring&quot;">​</a></h2><p>Tracks patient consent decisions during authorization flows.</p><h3 id="endpoints-—-monitoring-consent" tabindex="-1">Endpoints — <code>/monitoring/consent</code> <a class="header-anchor" href="#endpoints-—-monitoring-consent" aria-label="Permalink to &quot;Endpoints — `/monitoring/consent`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time consent decisions</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query events (filter: <code>limit</code>, <code>decision</code>, <code>clientId</code>, <code>patientId</code>, <code>resourceType</code>, <code>since</code>)</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot (last 24h)</td></tr><tr><td><code>GET</code></td><td><code>/events/export</code></td><td>REST</td><td>Download events as JSONL</td></tr></tbody></table><h3 id="websocket-transport-1" tabindex="-1">WebSocket Transport <a class="header-anchor" href="#websocket-transport-1" aria-label="Permalink to &quot;WebSocket Transport&quot;">​</a></h3><p>Available at <code>/consent/monitoring/websocket</code> with the same message protocol as the OAuth WebSocket.</p><h3 id="analytics-fields-1" tabindex="-1">Analytics Fields <a class="header-anchor" href="#analytics-fields-1" aria-label="Permalink to &quot;Analytics Fields&quot;">​</a></h3><ul><li><code>totalDecisions</code>, <code>permitRate</code>, <code>denyRate</code></li><li><code>averageCheckDuration</code>, <code>cacheHitRate</code></li><li><code>decisionsByMode</code> — enforce, audit-only, disabled</li><li><code>decisionsByResourceType</code> — e.g., Patient, Observation, MedicationRequest</li><li><code>topDeniedClients</code>, <code>topDeniedPatients</code></li><li><code>hourlyStats</code></li></ul><h3 id="event-fields" tabindex="-1">Event Fields <a class="header-anchor" href="#event-fields" aria-label="Permalink to &quot;Event Fields&quot;">​</a></h3><p>Each consent event includes:</p><ul><li><code>decision</code> (permit/deny), <code>enforced</code>, <code>mode</code></li><li><code>consentId</code>, <code>patientId</code>, <code>clientId</code></li><li><code>resourceType</code>, <code>method</code>, <code>reason</code></li><li><code>cached</code>, <code>checkDurationMs</code></li><li>IAL fields (Identity Assurance Level): <code>actualLevel</code>, <code>requiredLevel</code>, <code>sensitiveResource</code></li></ul><h3 id="log-files-2" tabindex="-1">Log Files <a class="header-anchor" href="#log-files-2" aria-label="Permalink to &quot;Log Files&quot;">​</a></h3><ul><li><code>logs/consent-metrics/consent-events.jsonl</code> — event log</li><li><code>logs/consent-metrics/consent-analytics.json</code> — latest analytics</li></ul><h2 id="admin-audit-monitoring" tabindex="-1">Admin Audit Monitoring <a class="header-anchor" href="#admin-audit-monitoring" aria-label="Permalink to &quot;Admin Audit Monitoring&quot;">​</a></h2><p>Tracks all admin mutations (create, update, delete actions) with actor identification.</p><h3 id="automatic-capture" tabindex="-1">Automatic Capture <a class="header-anchor" href="#automatic-capture" aria-label="Permalink to &quot;Automatic Capture&quot;">​</a></h3><p>The <code>adminAuditPlugin</code> middleware automatically captures all admin route mutations. No manual instrumentation needed — it hooks into the Elysia request lifecycle.</p><h3 id="endpoints-—-monitoring-admin-audit" tabindex="-1">Endpoints — <code>/monitoring/admin-audit</code> <a class="header-anchor" href="#endpoints-—-monitoring-admin-audit" aria-label="Permalink to &quot;Endpoints — `/monitoring/admin-audit`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/events/stream</code></td><td>SSE</td><td>Real-time audit events (mutations only)</td></tr><tr><td><code>GET</code></td><td><code>/analytics/stream</code></td><td>SSE</td><td>Real-time analytics updates</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>REST</td><td>Query events (filter: <code>limit</code>, <code>action</code>, <code>resource</code>, <code>actor</code>, <code>success</code>, <code>since</code>)</td></tr><tr><td><code>GET</code></td><td><code>/analytics</code></td><td>REST</td><td>Analytics snapshot</td></tr><tr><td><code>GET</code></td><td><code>/events/export</code></td><td>REST</td><td>Download full audit JSONL (streamed)</td></tr></tbody></table><h3 id="event-fields-1" tabindex="-1">Event Fields <a class="header-anchor" href="#event-fields-1" aria-label="Permalink to &quot;Event Fields&quot;">​</a></h3><ul><li><strong>Actor</strong>: <code>sub</code>, <code>username</code>, <code>email</code></li><li><strong>Request</strong>: <code>method</code>, <code>path</code>, <code>action</code> (create/update/delete/action/read)</li><li><strong>Target</strong>: <code>resource</code> domain, <code>resourceId</code></li><li><strong>Result</strong>: <code>statusCode</code>, <code>success</code>, <code>durationMs</code></li><li><code>ipAddress</code>, <code>detail</code></li></ul><h3 id="analytics-fields-2" tabindex="-1">Analytics Fields <a class="header-anchor" href="#analytics-fields-2" aria-label="Permalink to &quot;Analytics Fields&quot;">​</a></h3><ul><li><code>totalActions</code>, <code>successRate</code></li><li><code>actionsByType</code>, <code>actionsByResource</code></li><li><code>topActors</code> — most active admin users</li><li><code>hourlyStats</code></li><li><code>recentFailures</code> — last failed admin operations</li></ul><h3 id="log-files-3" tabindex="-1">Log Files <a class="header-anchor" href="#log-files-3" aria-label="Permalink to &quot;Log Files&quot;">​</a></h3><ul><li><code>logs/admin-audit/admin-audit.jsonl</code> — full audit log (replays last 7 days on startup)</li></ul><h2 id="system-status-health" tabindex="-1">System Status &amp; Health <a class="header-anchor" href="#system-status-health" aria-label="Permalink to &quot;System Status &amp; Health&quot;">​</a></h2><h3 id="get-health" tabindex="-1"><code>GET /health</code> <a class="header-anchor" href="#get-health" aria-label="Permalink to &quot;`GET /health`&quot;">​</a></h3><p>Lightweight liveness probe (30-second TTL cache). Returns:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ok&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;uptime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">86400</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="get-status" tabindex="-1"><code>GET /status</code> <a class="header-anchor" href="#get-status" aria-label="Permalink to &quot;`GET /status`&quot;">​</a></h3><p>Full system status check including:</p><ul><li><strong>FHIR Servers</strong> — per-server reachability and response time</li><li><strong>Keycloak</strong> — connection status, realm accessibility, last connected time</li><li><strong>Memory</strong> — heap usage, RSS, external</li><li><strong>Overall</strong> — aggregate health status</li></ul><p>Keycloak connection events are logged to <code>logs/keycloak/connections.jsonl</code> and <code>logs/keycloak/last-connection.json</code>.</p><h2 id="sse-stream-protocol" tabindex="-1">SSE Stream Protocol <a class="header-anchor" href="#sse-stream-protocol" aria-label="Permalink to &quot;SSE Stream Protocol&quot;">​</a></h2><p>All SSE streams follow the same pattern:</p><ol><li><strong>Connection event</strong> — sent immediately on connect<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;type&quot;:&quot;connection&quot;,&quot;message&quot;:&quot;Connected to ...&quot;,&quot;timestamp&quot;:&quot;...&quot;}</span></span></code></pre></div></li><li><strong>Data events</strong> — sent as they occur<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;id&quot;:&quot;...&quot;,&quot;type&quot;:&quot;...&quot;,&quot;timestamp&quot;:&quot;...&quot;}</span></span></code></pre></div></li><li><strong>Keepalive</strong> — every 30 seconds<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;type&quot;:&quot;keepalive&quot;,&quot;timestamp&quot;:&quot;...&quot;}</span></span></code></pre></div></li></ol><p>Streams automatically clean up when the client disconnects (detected via <code>controller.desiredSize === null</code>).</p><h2 id="log-directory-structure" tabindex="-1">Log Directory Structure <a class="header-anchor" href="#log-directory-structure" aria-label="Permalink to &quot;Log Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>logs/</span></span>\n<span class="line"><span>├── oauth-metrics/</span></span>\n<span class="line"><span>│   ├── oauth-events.jsonl</span></span>\n<span class="line"><span>│   ├── oauth-analytics.json</span></span>\n<span class="line"><span>│   └── system-health.json</span></span>\n<span class="line"><span>├── fhir-health/</span></span>\n<span class="line"><span>│   └── health-checks.jsonl</span></span>\n<span class="line"><span>├── consent-metrics/</span></span>\n<span class="line"><span>│   ├── consent-events.jsonl</span></span>\n<span class="line"><span>│   └── consent-analytics.json</span></span>\n<span class="line"><span>├── admin-audit/</span></span>\n<span class="line"><span>│   └── admin-audit.jsonl</span></span>\n<span class="line"><span>└── keycloak/</span></span>\n<span class="line"><span>    ├── connections.jsonl</span></span>\n<span class="line"><span>    └── last-connection.json</span></span></code></pre></div><p>All JSONL files use newline-delimited JSON (one object per line) and can be downloaded via the export endpoints.</p>',85)])])}const m=e(i,[["render",s]]);export{p as __pageData,m as default};
